CREATE  TRIGGER  tD_PRODUCT AFTER DELETE ON PRODUCT for each row
-- erwin Builtin Trigger
-- DELETE trigger on PRODUCT 
DECLARE NUMROWS INTEGER;
BEGIN
    /* erwin Builtin Trigger */
    /* APP.PRODUCT  OPS.ORDER_ITEM on parent delete restrict */
    /* ERWIN_RELATION:CHECKSUM="0000e092", PARENT_OWNER="APP", PARENT_TABLE="PRODUCT"
    CHILD_OWNER="OPS", CHILD_TABLE="ORDER_ITEM"
    P2C_VERB_PHRASE="", C2P_VERB_PHRASE="", 
    FK_CONSTRAINT="R_4", FK_COLUMNS="product_id" */
    SELECT count(*) INTO NUMROWS
      FROM OPS.ORDER_ITEM
      WHERE
        /*  %JoinFKPK(OPS.ORDER_ITEM,:%Old," = "," AND") */
        OPS.ORDER_ITEM.product_id = :old.product_id;
    IF (NUMROWS > 0)
    THEN
      raise_application_error(
        -20001,
        'Cannot delete APP.PRODUCT because OPS.ORDER_ITEM exists.'
      );
    END IF;


-- erwin Builtin Trigger
END;
/

CREATE  TRIGGER tU_PRODUCT AFTER UPDATE ON PRODUCT for each row
-- erwin Builtin Trigger
-- UPDATE trigger on PRODUCT 
DECLARE NUMROWS INTEGER;
BEGIN
  /* erwin Builtin Trigger */
  /* APP.PRODUCT  OPS.ORDER_ITEM on parent update restrict */
  /* ERWIN_RELATION:CHECKSUM="00010f92", PARENT_OWNER="APP", PARENT_TABLE="PRODUCT"
    CHILD_OWNER="OPS", CHILD_TABLE="ORDER_ITEM"
    P2C_VERB_PHRASE="", C2P_VERB_PHRASE="", 
    FK_CONSTRAINT="R_4", FK_COLUMNS="product_id" */
  IF
    /* %JoinPKPK(:%Old,:%New," <> "," OR ") */
    :old.product_id <> :new.product_id
  THEN
    SELECT count(*) INTO NUMROWS
      FROM OPS.ORDER_ITEM
      WHERE
        /*  %JoinFKPK(OPS.ORDER_ITEM,:%Old," = "," AND") */
        OPS.ORDER_ITEM.product_id = :old.product_id;
    IF (NUMROWS > 0)
    THEN 
      raise_application_error(
        -20005,
        'Cannot update APP.PRODUCT because OPS.ORDER_ITEM exists.'
      );
    END IF;
  END IF;


-- erwin Builtin Trigger
END;
