BEGIN
  /* erwin Builtin Trigger */
  /* APP.PROMOTION  APP.CAMPAIGN on parent update restrict */
  /* ERWIN_RELATION:CHECKSUM="0001259f", PARENT_OWNER="APP", PARENT_TABLE="PROMOTION"
    CHILD_OWNER="APP", CHILD_TABLE="CAMPAIGN"
    P2C_VERB_PHRASE="", C2P_VERB_PHRASE="", 
