CREATE  TRIGGER  tD_CUSTOMER AFTER DELETE ON CUSTOMER for each row
-- erwin Builtin Trigger
-- DELETE trigger on CUSTOMER 
DECLARE NUMROWS INTEGER;
BEGIN
    /* erwin Builtin Trigger */
    /* APP.CUSTOMER  APP.TRANSACTION_LOG on parent delete set null */
    /* ERWIN_RELATION:CHECKSUM="0001dc20", PARENT_OWNER="APP", PARENT_TABLE="CUSTOMER"
    CHILD_OWNER="APP", CHILD_TABLE="TRANSACTION_LOG"
    P2C_VERB_PHRASE="", C2P_VERB_PHRASE="", 
    FK_CONSTRAINT="R_5", FK_COLUMNS="customer_id" */
    UPDATE APP.TRANSACTION_LOG
      SET
        /* %SetFK(APP.TRANSACTION_LOG,NULL) */
        APP.TRANSACTION_LOG.customer_id = NULL
      WHERE
        /* %JoinFKPK(APP.TRANSACTION_LOG,:%Old," = "," AND") */
        APP.TRANSACTION_LOG.customer_id = :old.customer_id;

    /* erwin Builtin Trigger */
    /* APP.CUSTOMER  APP.ORDERS on parent delete restrict */
    /* ERWIN_RELATION:CHECKSUM="00000000", PARENT_OWNER="APP", PARENT_TABLE="CUSTOMER"
