    P2C_VERB_PHRASE="", C2P_VERB_PHRASE="", 
    FK_CONSTRAINT="R_2", FK_COLUMNS="customer_id" */
    SELECT count(*) INTO NUMROWS
      FROM APP.ORDERS
      WHERE
        /*  %JoinFKPK(APP.ORDERS,:%Old," = "," AND") */
        APP.ORDERS.customer_id = :old.customer_id;
    IF (NUMROWS > 0)
    THEN
      raise_application_error(
        -20001,
        'Cannot delete APP.CUSTOMER because APP.ORDERS exists.'
      );
    END IF;


-- erwin Builtin Trigger
END;
