CREATE OR REPLACE VIEW APP.VW_CUSTOMER_SUMMARY ( customer_id,full_name,email,email_verified ) 
	 AS  SELECT c.customer_id,c.full_name,c.email,c.email_verified
		FROM APP.CUSTOMER c;
